import { Context, Effect, FileSystem, Layer, ManagedRuntime, Path } from "effect";
import { IoLive } from "../io";
import { CommandExecutor, HttpClient, SocketBoundary } from "../io";

export type BackendClockService = {
  readonly nowIso: () => string;
  readonly nowMs: () => number;
};

export const BackendClock = Context.Service<BackendClockService>("relay/BackendClock");

export const BackendClockLive = Layer.succeed(BackendClock)({
  nowIso: () => new Date().toISOString(),
  nowMs: () => Date.now()
});

export type BackendConfigService = {
  readonly gitMetadataCacheTtlMs: number;
  readonly gitCommandTimeoutMs: number;
  readonly codexStatusTimeoutMs: number;
};

export const BackendConfig = Context.Service<BackendConfigService>("relay/BackendConfig");

export const BackendConfigLive = Layer.succeed(BackendConfig)({
  gitMetadataCacheTtlMs: 3_000,
  gitCommandTimeoutMs: 5_000,
  codexStatusTimeoutMs: 5_000
});

export type BackendLogLevel = "info" | "warn" | "error";

export type BackendServicesBase =
  | Context.Service.Identifier<typeof BackendClock>
  | Context.Service.Identifier<typeof BackendConfig>;
export type BackendIoServices =
  | Context.Service.Identifier<typeof FileSystem.FileSystem>
  | Context.Service.Identifier<typeof Path.Path>
  | Context.Service.Identifier<typeof CommandExecutor>
  | Context.Service.Identifier<typeof HttpClient>
  | Context.Service.Identifier<typeof SocketBoundary>;

export type BackendLoggerService = {
  readonly log: (
    level: BackendLogLevel,
    scope: string,
    message: string,
    meta?: unknown
  ) => Effect.Effect<void, unknown, BackendServicesBase | BackendIoServices>;
};

export const BackendLogger = Context.Service<BackendLoggerService>("relay/BackendLogger");

const safeJson = (value: unknown): string => {
  try {
    return JSON.stringify(value);
  } catch {
    return '"[unserializable]"';
  }
};

export const BackendLoggerConsoleLive = Layer.succeed(BackendLogger)({
  log: (level, scope, message, meta) =>
    Effect.gen(function*() {
      const clock = yield* BackendClock;
      const line = `${clock.nowIso()} ${level.toUpperCase()} [${scope}] ${message}${
        meta === undefined ? "" : ` ${safeJson(meta)}`
      }`;
      if (level === "error") {
        console.error(line);
      } else {
        console.log(line);
      }
    })
});

export const BackendServicesBaseLive = Layer.mergeAll(BackendClockLive, BackendConfigLive);

export const BackendRuntimeLive = Layer.mergeAll(BackendServicesBaseLive, BackendLoggerConsoleLive, IoLive);

export type BackendServices = BackendServicesBase | Context.Service.Identifier<typeof BackendLogger> | BackendIoServices;
export type BackendEffect<A, E = unknown, R = BackendServices> = Effect.Effect<A, E, R>;

let backendRuntime = ManagedRuntime.make(BackendRuntimeLive) as ManagedRuntime.ManagedRuntime<BackendServices, unknown>;

export const configureBackendRuntime = <R, E>(runtime: ManagedRuntime.ManagedRuntime<R, E>): void => {
  backendRuntime = runtime as unknown as ManagedRuntime.ManagedRuntime<BackendServices, unknown>;
};

export const disposeBackendRuntime = (): Promise<void> => backendRuntime.dispose();

export const runBackendEffect = <A, E, R>(effect: Effect.Effect<A, E, R>): Promise<A> =>
  backendRuntime.runPromise(effect as unknown as Effect.Effect<A, E, BackendServices>);

export const fromPromise = <A>(evaluate: (signal: AbortSignal) => PromiseLike<A>): Effect.Effect<A, unknown> =>
  Effect.tryPromise({
    try: evaluate,
    catch: (cause) => cause
  });

export const fromSync = <A>(evaluate: () => A): Effect.Effect<A, unknown> =>
  Effect.suspend(() => {
    try {
      return Effect.succeed(evaluate());
    } catch (cause) {
      return Effect.fail(cause);
    }
  });

import { Context, Effect, Layer } from "effect";
import type { GitMetadata } from "../../../shared/types";
import { BackendConfig, fromPromise, runBackendEffect } from "../runtime";
import { CommandExecutor, pathResolve, statPathEffect } from "../io";

export type GitCommandResult = {
  stdout: string;
  stderr: string;
};

export type GitCommandRunner = (projectPath: string, args: string[]) => Promise<GitCommandResult>;

type GitMetadataDependencies = {
  execGit?: GitCommandRunner;
  now?: () => string;
};

const defaultGitRunner: GitCommandRunner = (projectPath, args) =>
  runBackendEffect(
    CommandExecutor.use((executor) =>
      executor.execFile("git", ["-C", projectPath, ...args], {
        maxBuffer: 1024 * 1024,
        timeoutMs: 5_000
      })
    )
  );

const baseMetadata = (
  state: GitMetadata["state"],
  updatedAt: string,
  patch: Partial<Omit<GitMetadata, "state" | "updatedAt">> = {}
): GitMetadata => ({
  state,
  isGitRepository: false,
  branchName: null,
  isDetachedHead: false,
  commitSha: null,
  isDirty: false,
  changedFileCount: null,
  message: null,
  error: null,
  updatedAt,
  ...patch
});

const commandMessage = (error: unknown): string => {
  if (typeof error === "object" && error && "stderr" in error && typeof (error as { stderr?: unknown }).stderr === "string") {
    const stderr = (error as { stderr: string }).stderr.trim();
    if (stderr) return stderr.split("\n")[0];
  }
  if (error instanceof Error) return error.message;
  return "Git command failed.";
};

const isMissingGitBinary = (error: unknown): boolean =>
  typeof error === "object" && error !== null && "code" in error && (error as NodeJS.ErrnoException).code === "ENOENT";

const isNotGitRepositoryError = (error: unknown): boolean => /not a git repository|not a git dir/i.test(commandMessage(error));

const isUnbornHeadError = (error: unknown): boolean =>
  /needed a single revision|ambiguous argument 'HEAD'|unknown revision or path/i.test(commandMessage(error));

export const parsePorcelainChangedFileCount = (output: string): number => {
  const records = output.split("\0").filter((record) => record.length > 0);
  let count = 0;

  for (let index = 0; index < records.length; index += 1) {
    const record = records[index];
    if (record.length < 3) continue;
    count += 1;

    const stagedStatus = record[0];
    const unstagedStatus = record[1];
    if (stagedStatus === "R" || stagedStatus === "C" || unstagedStatus === "R" || unstagedStatus === "C") {
      index += 1;
    }
  }

  return count;
};

const readGitMetadataPromise = async (
  projectPath: string,
  dependencies: GitMetadataDependencies = {}
): Promise<GitMetadata> => {
  const resolved = pathResolve(projectPath);
  const execGit = dependencies.execGit ?? defaultGitRunner;
  const updatedAt = dependencies.now?.() ?? new Date().toISOString();

  try {
    const info = await runBackendEffect(statPathEffect(resolved));
    if (!info.isDirectory) {
      return baseMetadata("missing", updatedAt, {
        message: "Project path is not a directory."
      });
    }
  } catch (error) {
    return baseMetadata("missing", updatedAt, {
      message: error instanceof Error ? error.message : "Project path is unavailable.",
      error: error instanceof Error ? error.message : "Project path is unavailable."
    });
  }

  try {
    const insideWorkTree = (await execGit(resolved, ["rev-parse", "--is-inside-work-tree"])).stdout.trim();
    if (insideWorkTree !== "true") {
      return baseMetadata("not_git", updatedAt, {
        message: "Project path is not a Git repository."
      });
    }
  } catch (error) {
    if (isMissingGitBinary(error)) {
      return baseMetadata("unavailable", updatedAt, {
        message: "Git command is unavailable.",
        error: commandMessage(error)
      });
    }
    if (isNotGitRepositoryError(error)) {
      return baseMetadata("not_git", updatedAt, {
        message: "Project path is not a Git repository."
      });
    }
    return baseMetadata("error", updatedAt, {
      message: "Unable to inspect Git repository.",
      error: commandMessage(error)
    });
  }

  let branchName: string | null = null;
  let commitSha: string | null = null;

  try {
    branchName = (await execGit(resolved, ["branch", "--show-current"])).stdout.trim() || null;

    try {
      commitSha = (await execGit(resolved, ["rev-parse", "--short=8", "HEAD"])).stdout.trim() || null;
    } catch (error) {
      if (!isUnbornHeadError(error)) throw error;
    }

    const statusOutput = (await execGit(resolved, ["status", "--porcelain=v1", "-z", "--untracked-files=all"])).stdout;
    const changedFileCount = parsePorcelainChangedFileCount(statusOutput);
    const isDetachedHead = branchName === null && commitSha !== null;

    return baseMetadata("ready", updatedAt, {
      isGitRepository: true,
      branchName,
      isDetachedHead,
      commitSha,
      isDirty: changedFileCount > 0,
      changedFileCount,
      message: changedFileCount > 0 ? `${changedFileCount} uncommitted file change(s).` : "Working tree clean."
    });
  } catch (error) {
    if (isMissingGitBinary(error)) {
      return baseMetadata("unavailable", updatedAt, {
        message: "Git command is unavailable.",
        error: commandMessage(error)
      });
    }
    return baseMetadata("error", updatedAt, {
      isGitRepository: true,
      branchName,
      isDetachedHead: branchName === null && commitSha !== null,
      commitSha,
      message: "Unable to inspect Git repository.",
      error: commandMessage(error)
    });
  }
};

const gitMetadataCache = new Map<string, { value?: GitMetadata; expiresAt: number; pending?: Promise<GitMetadata> }>();

const readCachedGitMetadataPromise = async (
  projectPath: string,
  options: { force?: boolean; cacheTtlMs?: number } = {}
): Promise<GitMetadata> => {
  const resolved = pathResolve(projectPath);
  const cached = gitMetadataCache.get(resolved);
  const now = Date.now();

  if (!options.force && cached?.value && cached.expiresAt > now) {
    return cached.value;
  }
  if (!options.force && cached?.pending) {
    return cached.pending;
  }

  const pending = readGitMetadataPromise(resolved).then((value) => {
    gitMetadataCache.set(resolved, {
      value,
      expiresAt: Date.now() + (options.cacheTtlMs ?? 3_000)
    });
    return value;
  });

  gitMetadataCache.set(resolved, {
    value: cached?.value,
    expiresAt: cached?.expiresAt ?? 0,
    pending
  });

  return pending;
};

const clearGitMetadataCacheSync = (): void => {
  gitMetadataCache.clear();
};

export type GitServiceService = {
  readonly readMetadata: (projectPath: string, dependencies?: GitMetadataDependencies) => Effect.Effect<GitMetadata, unknown>;
  readonly readCachedMetadata: (
    projectPath: string,
    options?: { force?: boolean }
  ) => Effect.Effect<GitMetadata, unknown, Context.Service.Identifier<typeof BackendConfig>>;
  readonly clearCache: () => Effect.Effect<void>;
};

export const GitService = Context.Service<GitServiceService>("relay/GitService");

export const GitServiceLive = Layer.succeed(GitService)({
  readMetadata: (projectPath, dependencies = {}) => fromPromise(() => readGitMetadataPromise(projectPath, dependencies)),
  readCachedMetadata: (projectPath, options = {}) =>
    Effect.gen(function*() {
      const config = yield* BackendConfig;
      return yield* fromPromise(() => readCachedGitMetadataPromise(projectPath, { ...options, cacheTtlMs: config.gitMetadataCacheTtlMs }));
    }),
  clearCache: () => Effect.sync(clearGitMetadataCacheSync)
});

export const readGitMetadata = (projectPath: string, dependencies: GitMetadataDependencies = {}): Promise<GitMetadata> =>
  runBackendEffect(Effect.provide(GitService.use((service) => service.readMetadata(projectPath, dependencies)), GitServiceLive));

export const readCachedGitMetadata = (projectPath: string, options: { force?: boolean } = {}): Promise<GitMetadata> =>
  runBackendEffect(Effect.provide(GitService.use((service) => service.readCachedMetadata(projectPath, options)), GitServiceLive));

export const clearGitMetadataCache = (): void => {
  clearGitMetadataCacheSync();
};

import { createRequire } from "node:module";
import { CommandExecutor, pathDirname, pathJoin } from "../io";
import { runBackendEffect } from "../runtime";

export type CodexCliCandidateSource = "bundled" | "path";

export type CodexCliCandidate = {
  source: CodexCliCandidateSource;
  command: string;
};

export type CodexCliResolution = {
  candidate: CodexCliCandidate;
  version: string;
};

export type ResolvePackageJson = (specifier: string, fromPackageJsonPath?: string) => string;

export type ResolveBundledCodexPathOptions = {
  platform?: NodeJS.Platform;
  arch?: NodeJS.Architecture;
  resolvePackageJson?: ResolvePackageJson;
};

export type ResolveCodexCliCandidatesOptions = ResolveBundledCodexPathOptions & {
  pathCommand?: string;
};

export type ResolveAvailableCodexCliDependencies = {
  resolveCandidates?: () => readonly CodexCliCandidate[];
  runVersion?: (candidate: CodexCliCandidate) => Promise<string>;
};

const CODEX_NPM_NAME = "@openai/codex";
const CODEX_PATH_COMMAND = "codex";

const PLATFORM_PACKAGE_BY_TARGET: Record<string, string> = {
  "x86_64-unknown-linux-musl": "@openai/codex-linux-x64",
  "aarch64-unknown-linux-musl": "@openai/codex-linux-arm64",
  "x86_64-apple-darwin": "@openai/codex-darwin-x64",
  "aarch64-apple-darwin": "@openai/codex-darwin-arm64",
  "x86_64-pc-windows-msvc": "@openai/codex-win32-x64",
  "aarch64-pc-windows-msvc": "@openai/codex-win32-arm64"
};

export const targetTripleForPlatform = (platform: NodeJS.Platform, arch: NodeJS.Architecture): string | null => {
  switch (platform) {
    case "linux":
    case "android":
      switch (arch) {
        case "x64":
          return "x86_64-unknown-linux-musl";
        case "arm64":
          return "aarch64-unknown-linux-musl";
        default:
          return null;
      }
    case "darwin":
      switch (arch) {
        case "x64":
          return "x86_64-apple-darwin";
        case "arm64":
          return "aarch64-apple-darwin";
        default:
          return null;
      }
    case "win32":
      switch (arch) {
        case "x64":
          return "x86_64-pc-windows-msvc";
        case "arm64":
          return "aarch64-pc-windows-msvc";
        default:
          return null;
      }
    default:
      return null;
  }
};

const defaultResolvePackageJson: ResolvePackageJson = (specifier, fromPackageJsonPath) => {
  const requireFrom = fromPackageJsonPath ?? (typeof __filename === "string" ? __filename : import.meta.url);
  return createRequire(requireFrom).resolve(specifier);
};

export const resolveBundledCodexPath = (options: ResolveBundledCodexPathOptions = {}): string | null => {
  const platform = options.platform ?? process.platform;
  const arch = options.arch ?? process.arch;
  const targetTriple = targetTripleForPlatform(platform, arch);
  if (!targetTriple) return null;

  const platformPackage = PLATFORM_PACKAGE_BY_TARGET[targetTriple];
  if (!platformPackage) return null;

  const resolvePackageJson = options.resolvePackageJson ?? defaultResolvePackageJson;
  try {
    const codexPackageJsonPath = resolvePackageJson(`${CODEX_NPM_NAME}/package.json`);
    const platformPackageJsonPath = resolvePackageJson(`${platformPackage}/package.json`, codexPackageJsonPath);
    const codexBinaryName = platform === "win32" ? "codex.exe" : "codex";
    return pathJoin(pathDirname(platformPackageJsonPath), "vendor", targetTriple, "codex", codexBinaryName);
  } catch {
    return null;
  }
};

export const resolveCodexCliCandidates = (options: ResolveCodexCliCandidatesOptions = {}): CodexCliCandidate[] => {
  const pathCommand = options.pathCommand ?? CODEX_PATH_COMMAND;
  const bundledPath = resolveBundledCodexPath(options);
  const candidates: CodexCliCandidate[] = [];
  if (bundledPath) {
    candidates.push({ source: "bundled", command: bundledPath });
  }
  candidates.push({ source: "path", command: pathCommand });
  return candidates;
};

export const runCodexVersion = async (candidate: CodexCliCandidate): Promise<string> => {
  const { stdout } = await runBackendEffect(
    CommandExecutor.use((executor) => executor.execFile(candidate.command, ["--version"], { timeoutMs: 5_000 }))
  );
  return stdout.trim();
};

export const resolveAvailableCodexCli = async (
  dependencies: ResolveAvailableCodexCliDependencies = {}
): Promise<CodexCliResolution | null> => {
  const candidates = dependencies.resolveCandidates?.() ?? resolveCodexCliCandidates();
  const runVersion = dependencies.runVersion ?? runCodexVersion;

  for (const candidate of candidates) {
    try {
      const version = (await runVersion(candidate)).trim();
      return { candidate, version };
    } catch {
      // Try the next candidate.
    }
  }

  return null;
};

